#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define fp double

#define NUMBER_PAR_PER_BOX 100

#ifdef RD_WG_SIZE_0_0
    #define NUMBER_THREADS RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
    #define NUMBER_THREADS RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
    #define NUMBER_THREADS RD_WG_SIZE
#else
    #define NUMBER_THREADS 128
#endif

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct
{
    fp x, y, z;
} THREE_VECTOR;

typedef struct
{
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str
{
    int x, y, z;
    int number;
    long offset;

    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str
{
    fp alpha;
} par_str;

typedef struct dim_str
{
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;

    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

#ifdef __cplusplus
extern "C" {
#endif
long long get_time();
void setdevice(void);
void checkCUDAError(const char *msg);
#ifdef __cplusplus
}
#endif

__global__ void kernel_gpu_cuda(box_str* box,
                                FOUR_VECTOR* rv,
                                fp* qv,
                                FOUR_VECTOR* fv,
                                fp a2,
                                long number_boxes)
{
    long l = (long)blockIdx.x;
    int i = threadIdx.x;

    if (l >= number_boxes || i >= NUMBER_PAR_PER_BOX) {
        return;
    }

    long first_i = box[l].offset;
    FOUR_VECTOR rAi = rv[first_i + i];
    FOUR_VECTOR fAi = fv[first_i + i];

    for (int k = 0; k < (1 + box[l].nn); k++) {

        int pointer;
        if (k == 0) {
            pointer = (int)l;
        } else {
            pointer = box[l].nei[k - 1].number;
        }

        long first_j = box[pointer].offset;

        for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {

            FOUR_VECTOR rBj = rv[first_j + j];
            fp qBj = qv[first_j + j];

            fp r2 = rAi.v + rBj.v - DOT(rAi, rBj);
            fp u2 = a2 * r2;
            fp vij = exp(-u2);
            fp fs = 2.0 * vij;

            THREE_VECTOR d;
            d.x = rAi.x - rBj.x;
            d.y = rAi.y - rBj.y;
            d.z = rAi.z - rBj.z;

            fp fxij = fs * d.x;
            fp fyij = fs * d.y;
            fp fzij = fs * d.z;

            fAi.v += qBj * vij;
            fAi.x += qBj * fxij;
            fAi.y += qBj * fyij;
            fAi.z += qBj * fzij;
        }
    }

    fv[first_i + i] = fAi;
}

static void kernel_cuda_common(par_str par,
                               dim_str dim,
                               box_str* box,
                               FOUR_VECTOR* rv,
                               fp* qv,
                               FOUR_VECTOR* fv)
{
    long long time0;
    time0 = get_time();

    long long time1;
    long long time2;
    long long time3;
    long long time4;

    fp alpha;
    fp a2;

    box_str* d_box = NULL;
    FOUR_VECTOR* d_rv = NULL;
    fp* d_qv = NULL;
    FOUR_VECTOR* d_fv = NULL;

    time1 = get_time();

    setdevice();

    time2 = get_time();

    alpha = par.alpha;
    a2 = 2.0 * alpha * alpha;

    cudaMalloc((void**)&d_box, dim.box_mem);
    checkCUDAError("cudaMalloc d_box");
    cudaMalloc((void**)&d_rv, dim.space_mem);
    checkCUDAError("cudaMalloc d_rv");
    cudaMalloc((void**)&d_qv, dim.space_mem2);
    checkCUDAError("cudaMalloc d_qv");
    cudaMalloc((void**)&d_fv, dim.space_mem);
    checkCUDAError("cudaMalloc d_fv");

    cudaMemcpy(d_box, box, dim.box_mem, cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy box H2D");
    cudaMemcpy(d_rv, rv, dim.space_mem, cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy rv H2D");
    cudaMemcpy(d_qv, qv, dim.space_mem2, cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy qv H2D");
    cudaMemcpy(d_fv, fv, dim.space_mem, cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy fv H2D");

    time3 = get_time();

    kernel_gpu_cuda<<<(unsigned int)dim.number_boxes, NUMBER_THREADS>>>(d_box,
                                                                        d_rv,
                                                                        d_qv,
                                                                        d_fv,
                                                                        a2,
                                                                        dim.number_boxes);
    checkCUDAError("kernel_gpu_cuda launch");
    cudaDeviceSynchronize();
    checkCUDAError("kernel_gpu_cuda sync");

    cudaMemcpy(fv, d_fv, dim.space_mem, cudaMemcpyDeviceToHost);
    checkCUDAError("cudaMemcpy fv D2H");

    cudaFree(d_box);
    cudaFree(d_rv);
    cudaFree(d_qv);
    cudaFree(d_fv);

    time4 = get_time();

    printf("Time spent in different stages of CPU/MCPU KERNEL:\n");

    printf("%15.12f s, %15.12f % : CPU/MCPU: VARIABLES\n", (float)(time1-time0) / 1000000, (float)(time1-time0) / (float)(time4-time0) * 100);
    printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n", (float)(time2-time1) / 1000000, (float)(time2-time1) / (float)(time4-time0) * 100);
    printf("%15.12f s, %15.12f % : CPU/MCPU: INPUTS\n", (float)(time3-time2) / 1000000, (float)(time3-time2) / (float)(time4-time0) * 100);
    printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n", (float)(time4-time3) / 1000000, (float)(time4-time3) / (float)(time4-time0) * 100);

    printf("Total time:\n");
    printf("%.12f s\n", (float)(time4-time0) / 1000000);
}

#ifdef __cplusplus
extern "C" {
#endif

void kernel_cpu(par_str par,
                dim_str dim,
                box_str* box,
                FOUR_VECTOR* rv,
                fp* qv,
                FOUR_VECTOR* fv)
{
    kernel_cuda_common(par, dim, box, rv, qv, fv);
}

void kernel_gpu_cuda_wrapper(par_str par,
                             dim_str dim,
                             box_str* box,
                             FOUR_VECTOR* rv,
                             fp* qv,
                             FOUR_VECTOR* fv)
{
    kernel_cuda_common(par, dim, box, rv, qv, fv);
}

#ifdef __cplusplus
}
#endif

